if (!context) {
                context = make_shared<CryptoContext>(*get_params());
                KeyGenerator keygen(*context->context());
                context->set_secret(keygen.secret_key());
                RelinKeys rlk;
                keygen.create_relin_keys(rlk);
                context->set_evaluator(move(rlk));
            }
